# -*- coding: utf-8 -*-
"""?????????????????????"""
import base64
import io
import os
import shutil
import zipfile
from pathlib import Path

TARGET = Path('/opt/postgrad-contact-manager')
BACKUP = Path('/opt/postgrad-contact-manager-sync-backup')
PAYLOAD = """

""".strip()


def main():
    if not TARGET.exists():
        raise SystemExit(f'???????: {TARGET}')

    if BACKUP.exists():
        shutil.rmtree(BACKUP)
    shutil.copytree(TARGET, BACKUP, ignore=shutil.ignore_patterns('node_modules', 'dist', 'data'))

    raw = base64.b64decode(PAYLOAD)
    with zipfile.ZipFile(io.BytesIO(raw)) as zf:
        zf.extractall(TARGET)

    print('SYNC_DONE')
    print(f'target={TARGET}')
    print(f'backup={BACKUP}')


if __name__ == '__main__':
    main()
